create or replace function public.create_supplier_quote(p_organization_id uuid,p_purchase_request_id uuid,p_supplier_id uuid,p_supplier_reference text,p_quote_date date,p_valid_until date,p_notes text,p_lines jsonb,p_actor_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$ declare v_id uuid; v_no text; line jsonb; v_product uuid; v_warehouse uuid; v_description text; v_qty numeric; v_cost numeric; v_tax_rate numeric; v_subtotal numeric:=0; v_tax numeric:=0; v_line_subtotal numeric; v_line_tax numeric; begin if p_actor_id is distinct from auth.uid() then raise exception 'Actor mismatch'; end if; if not public.has_org_role(p_organization_id,array['owner','admin','accountant','inventory','manager']::public.app_role[]) then raise exception 'Insufficient purchasing permission'; end if; if not exists(select 1 from public.purchase_requests where id=p_purchase_request_id and organization_id=p_organization_id and status='approved') then raise exception 'Approved purchase request not found'; end if; if not exists(select 1 from public.suppliers where id=p_supplier_id and organization_id=p_organization_id and is_active) then raise exception 'Supplier not found'; end if; if jsonb_typeof(p_lines)<>'array' or jsonb_array_length(p_lines)=0 then raise exception 'Supplier quote requires lines'; end if; v_no:=public.next_document_number(p_organization_id,'RFQ'); insert into public.supplier_quotes(organization_id,purchase_request_id,supplier_id,quote_number,supplier_reference,quote_date,valid_until,status,notes,created_by) values(p_organization_id,p_purchase_request_id,p_supplier_id,v_no,nullif(trim(p_supplier_reference),''),coalesce(p_quote_date,current_date),p_valid_until,'received',nullif(trim(p_notes),''),p_actor_id) returning id into v_id; for line in select value from jsonb_array_elements(p_lines) loop v_product:=nullif(line->>'productId','')::uuid; v_warehouse:=nullif(line->>'warehouseId','')::uuid; v_description:=nullif(trim(line->>'description'),''); v_qty:=coalesce((line->>'quantity')::numeric,0); v_cost:=coalesce((line->>'unitCost')::numeric,0); v_tax_rate:=coalesce((line->>'taxRate')::numeric,0); if v_product is not null then select name into v_description from public.products where id=v_product and organization_id=p_organization_id and is_active; if not found then raise exception 'Product not found'; end if; end if; if v_description is null or v_qty<=0 or v_cost<0 or v_tax_rate<0 or v_tax_rate>100 then raise exception 'Invalid quote line'; end if; v_line_subtotal:=round(v_qty*v_cost,2); v_line_tax:=round(v_line_subtotal*v_tax_rate/100,2); v_subtotal:=v_subtotal+v_line_subtotal; v_tax:=v_tax+v_line_tax; insert into public.supplier_quote_items(organization_id,supplier_quote_id,product_id,warehouse_id,description,quantity,unit_cost,tax_rate,line_subtotal,line_tax) values(p_organization_id,v_id,v_product,v_warehouse,v_description,v_qty,v_cost,v_tax_rate,v_line_subtotal,v_line_tax); end loop; update public.supplier_quotes set subtotal=v_subtotal,tax_amount=v_tax where id=v_id; insert into public.audit_events(organization_id,actor_id,action,entity_type,entity_id,metadata) values(p_organization_id,p_actor_id,'purchasing.quote.received','supplier_quote',v_id,jsonb_build_object('number',v_no,'total',v_subtotal+v_tax)); return jsonb_build_object('id',v_id,'number',v_no,'total',v_subtotal+v_tax); end $$;

create or replace function public.convert_supplier_quote_to_order(p_organization_id uuid,p_supplier_quote_id uuid,p_order_date date,p_expected_date date,p_actor_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$ declare q public.supplier_quotes%rowtype; r public.purchase_requests%rowtype; v_id uuid; v_no text; begin if p_actor_id is distinct from auth.uid() then raise exception 'Actor mismatch'; end if; if not public.has_org_role(p_organization_id,array['owner','admin','accountant','manager']::public.app_role[]) then raise exception 'Insufficient order approval permission'; end if; select * into q from public.supplier_quotes where id=p_supplier_quote_id and organization_id=p_organization_id for update; if not found or q.status not in ('received','selected') then raise exception 'Supplier quote is not available'; end if; select * into r from public.purchase_requests where id=q.purchase_request_id and organization_id=p_organization_id for update; if not found or r.status<>'approved' then raise exception 'Approved request not found'; end if; v_no:=public.next_document_number(p_organization_id,'PO'); insert into public.purchase_orders(organization_id,branch_id,supplier_id,purchase_request_id,supplier_quote_id,order_number,order_date,expected_date,status,subtotal,tax_amount,notes,created_by,approved_by,approved_at) values(p_organization_id,r.branch_id,q.supplier_id,r.id,q.id,v_no,coalesce(p_order_date,current_date),p_expected_date,'approved',q.subtotal,q.tax_amount,q.notes,p_actor_id,p_actor_id,now()) returning id into v_id; insert into public.purchase_order_items(organization_id,purchase_order_id,product_id,warehouse_id,description,quantity,unit_cost,tax_rate,line_subtotal,line_tax) select organization_id,v_id,product_id,warehouse_id,description,quantity,unit_cost,tax_rate,line_subtotal,line_tax from public.supplier_quote_items where supplier_quote_id=q.id; update public.supplier_quotes set status='converted',updated_at=now() where id=q.id; update public.purchase_requests set status='converted',updated_at=now() where id=r.id; insert into public.audit_events(organization_id,actor_id,action,entity_type,entity_id,metadata) values(p_organization_id,p_actor_id,'purchasing.order.created','purchase_order',v_id,jsonb_build_object('number',v_no,'quote',q.quote_number,'total',q.total)); return jsonb_build_object('id',v_id,'number',v_no,'total',q.total); end $$;

revoke all on function public.create_supplier_quote(uuid,uuid,uuid,text,date,date,text,jsonb,uuid) from public; grant execute on function public.create_supplier_quote(uuid,uuid,uuid,text,date,date,text,jsonb,uuid) to authenticated;
revoke all on function public.convert_supplier_quote_to_order(uuid,uuid,date,date,uuid) from public; grant execute on function public.convert_supplier_quote_to_order(uuid,uuid,date,date,uuid) to authenticated;